#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        double Px, Py, Pz, Qx, Qy, Qz, dx, dy, dz, cx, cy, cz, r;
        scanf("%lf %lf %lf %lf %lf %lf %lf %lf %lf %lf %lf %lf %lf", &Px, &Py, &Pz, &Qx, &Qy, &Qz, &dx, &dy, &dz, &cx, &cy, &cz, &r);
        double a = dx * dx + dy * dy + dz * dz;
        double b = 2 * (dx * (Qx - cx) + dy * (Qy - cy) + dz * (Qz - cz));
        double c = (Qx - cx) * (Qx - cx) + (Qy - cy) * (Qy - cy) + (Qz - cz) * (Qz - cz) - r * r;
        double D = b * b - 4 * a * c;
        if (D >= 0) {
            double t = (-b - sqrt(D)) / (2 * a);
            if (t > 0) {
                printf("%.10f\n", t);
            } else {
                printf("%.10f\n", (-b + sqrt(D)) / (2 * a));
            }
        }
    }
    return 0;
}

